What does this program print?

```cpp
#include <iostream>

bool isOdd(int n)
{
    return n % 2 != 0;
}

int main()
{
    int x { 4 };

    if (isOdd(x) == false)
        std::cout << "Even\n";
    else
        std::cout << "Odd\n";

    return 0;
}
```
